@layer mergora.components {
  .mrg-item {
    display: flex;
    align-items: center;
    gap: var(--mrg-semantic-space-inline-md);
    min-block-size: var(--mrg-semantic-density-row-height);
    padding: var(--mrg-semantic-space-inset-sm) var(--mrg-semantic-space-inset-md);
    border-block-end: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-default);
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    font-family: var(--mrg-semantic-font-family-prose);
    transition: background-color var(--mrg-semantic-motion-duration-feedback)
      var(--mrg-semantic-motion-easing-standard);
  }
  .mrg-item[data-selected] {
    border-color: var(--mrg-semantic-color-selection-border);
    background: var(--mrg-semantic-color-selection-background);
    color: var(--mrg-semantic-color-selection-foreground);
  }
  .mrg-item[data-current] {
    box-shadow: inset 0 calc(var(--mrg-semantic-border-width-strong) * -1) 0
      var(--mrg-semantic-color-brand-violet);
  }
  .mrg-item__media {
    flex: none;
  }
  .mrg-item__body {
    min-inline-size: 0;
    flex: 1;
  }
  .mrg-item__title {
    font-size: var(--mrg-semantic-font-size-body);
    font-weight: var(--mrg-semantic-font-weight-strong);
    overflow-wrap: anywhere;
  }
  .mrg-item__description {
    color: var(--mrg-semantic-color-foreground-muted);
    font-size: var(--mrg-semantic-font-size-label);
    line-height: var(--mrg-semantic-font-line-height-body);
    overflow-wrap: anywhere;
  }
  .mrg-item__context {
    display: block;
    margin-block-start: var(--mrg-semantic-space-stack-xs);
    color: var(--mrg-semantic-color-brand-action);
    font-size: var(--mrg-semantic-font-size-caption);
    font-weight: var(--mrg-semantic-font-weight-label);
  }
  .mrg-item__visually-hidden {
    position: absolute;
    inline-size: 1px;
    block-size: 1px;
    overflow: hidden;
    clip-path: inset(50%);
    white-space: nowrap;
  }
  .mrg-item__actions {
    display: flex;
    flex: none;
    flex-wrap: wrap;
    gap: var(--mrg-semantic-density-control-gap);
  }
  .mrg-item :where(button, a):focus-visible {
    box-shadow: 0 0 0 var(--mrg-semantic-focus-width)
      var(--mrg-semantic-color-focus-contrast-background);
    outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
    outline-offset: var(--mrg-semantic-focus-offset);
  }
  @media (max-width: 30rem) {
    .mrg-item {
      align-items: flex-start;
      flex-wrap: wrap;
    }
    .mrg-item__actions {
      inline-size: 100%;
      padding-inline-start: calc(
        var(--mrg-semantic-size-icon-md) + var(--mrg-semantic-space-inline-md)
      );
    }
  }
  @media (prefers-reduced-motion: reduce) {
    .mrg-item {
      transition: none;
    }
  }
  @media (forced-colors: active) {
    .mrg-item {
      border-color: CanvasText;
      color: CanvasText;
      background: Canvas;
    }
    .mrg-item[data-selected] {
      outline: var(--mrg-semantic-border-width-strong) solid Highlight;
    }
    .mrg-item[data-current] {
      box-shadow: inset 0 calc(var(--mrg-semantic-border-width-strong) * -1) 0 Highlight;
    }
    .mrg-item :where(button, a):focus-visible {
      box-shadow: none;
      outline-color: Highlight;
    }
  }
}

import "./item.css";

import { Fragment, forwardRef, isValidElement, type HTMLAttributes, type ReactNode } from "react";

function hasContent(value: ReactNode): boolean {
  if (value === null || value === undefined || typeof value === "boolean") return false;
  if (typeof value === "string") return value.trim().length > 0;
  if (Array.isArray(value)) return value.some(hasContent);
  if (isValidElement<{ readonly children?: ReactNode }>(value)) {
    if (value.type === Fragment) return hasContent(value.props.children);
    return typeof value.type === "string" ? hasContent(value.props.children) : true;
  }
  return true;
}

function classes(...values: readonly (string | undefined | false)[]): string {
  return values.filter((value): value is string => Boolean(value)).join(" ");
}

export interface ItemProps extends Omit<HTMLAttributes<HTMLElement>, "title"> {
  /** Native container element used for the item; defaults to div. */
  readonly as?: "div" | "li" | "article";
  /** Optional leading media content; empty content removes its wrapper. */
  readonly media?: ReactNode;
  /** Primary visible content that names the item. */
  readonly title: ReactNode;
  /** Optional supporting copy rendered below the title when non-empty. */
  readonly description?: ReactNode;
  /** Optional trailing controls or links rendered in the action region when non-empty. */
  readonly actions?: ReactNode;
  /** Marks the item visually selected and adds text context before the title. */
  readonly selected?: boolean;
  /** Marks the item as the current destination through aria-current and family styling. */
  readonly current?: boolean;
  /** Adds optional state-specific output; omitting it removes the output region entirely. */
  readonly renderSelectionContext?: (state: {
    /** Whether the item currently carries the selected treatment. */
    readonly selected: boolean;
    /** Whether the item currently represents the user's destination. */
    readonly current: boolean;
  }) => ReactNode;
}

export const Item = forwardRef<HTMLElement, ItemProps>(function Item(
  {
    as: Element = "div",
    media,
    title,
    description,
    actions,
    selected = false,
    current = false,
    renderSelectionContext,
    className,
    ...props
  },
  ref,
) {
  const context = renderSelectionContext?.({ selected, current });
  return (
    <Element
      {...props}
      ref={ref as never}
      aria-current={current ? "true" : undefined}
      className={classes("mrg-item", className)}
      data-slot="item"
      data-selected={selected || undefined}
      data-current={current || undefined}
    >
      {hasContent(media) ? (
        <div className="mrg-item__media" data-slot="item-media">
          {media}
        </div>
      ) : null}
      <div className="mrg-item__body" data-slot="item-body">
        <div className="mrg-item__title" data-slot="item-title">
          {selected ? <span className="mrg-item__visually-hidden">Selected. </span> : null}
          {title}
        </div>
        {hasContent(description) ? (
          <div className="mrg-item__description" data-slot="item-description">
            {description}
          </div>
        ) : null}
        {hasContent(context) ? (
          <output className="mrg-item__context" data-slot="item-selection-context">
            {context}
          </output>
        ) : null}
      </div>
      {hasContent(actions) ? (
        <div className="mrg-item__actions" data-slot="item-actions">
          {actions}
        </div>
      ) : null}
    </Element>
  );
});
